-- 5. Keywords (10) + paper_keyword junction
-- Upsert by NormalizedText; skip if already linked

--   Keyword: Boosting (machine learning)
DECLARE @KeywordID UNIQUEIDENTIFIER;
IF EXISTS (SELECT 1 FROM KEYWORD WHERE NormalizedText = N'boosting (machine learning)')
BEGIN
    SET @KeywordID = (SELECT KeywordID FROM KEYWORD WHERE NormalizedText = N'boosting (machine learning)');
    -- Increment paper count
    UPDATE KEYWORD SET PaperCount = PaperCount + 1 WHERE KeywordID = @KeywordID;
END
ELSE
BEGIN
    SET @KeywordID = NEWID();
    INSERT INTO KEYWORD (KeywordID, FieldID, KeywordText, NormalizedText, PaperCount)
    VALUES (@KeywordID, @FieldID, N'Boosting (machine learning)', N'boosting (machine learning)', 1);
END

-- Link paper-keyword (skip if already exists)
IF NOT EXISTS (SELECT 1 FROM PAPER_KEYWORD WHERE PaperID = @PaperID AND KeywordID = @KeywordID)
BEGIN
    INSERT INTO PAPER_KEYWORD (PaperID, KeywordID, RelevanceScore)
    VALUES (@PaperID, @KeywordID, 0.8715);
END
GO

